"""
Declarative app factory for SRT simulator dashboards.

Define an entire Dash app via AppConfig — params, plots, and ports —
and build_app() generates the complete application.
"""

from dataclasses import dataclass, field
from collections import OrderedDict

from dash import Dash, dcc, html, Input, Output, State

from srt_dash.client import SimulatorClient
from srt_dash import components as C


@dataclass
class TraceDef:
    """One trace (line) on a plot."""
    signal: str             # signal name from stream (e.g. "can_state.Theta1")
    label: str              # display name (e.g. "theta1")
    mode: str = "lines"     # "lines", "markers", "lines+markers"


@dataclass
class PlotDef:
    """One graph panel in the 2x2 grid."""
    graph_id: str
    title: str
    traces: list            # list of TraceDef
    xaxis: str = "Time [s]"
    yaxis: str = ""
    x_signal: str = "Time"  # signal for x-axis (override for cross-plots)
    user_selectable: bool = True  # show searchable signal picker


@dataclass
class ParamDef:
    """One tunable parameter in the sidebar."""
    key: str                # param name sent to Julia (e.g. "m1", "Tau1_amplitude")
    label: str              # display label
    min: float = 0.0
    max: float = 1.0
    step: float = 0.1
    default: float = 0.0
    kind: str = "slider"    # "slider" or "dropdown"
    options: list = None    # for dropdowns: [("Off", 0), ("Sine", 1), ...]
    group: str = ""         # section header (params with same group are grouped)


@dataclass
class AppConfig:
    """Complete configuration for a simulator Dash app."""
    title: str
    port: int
    stream_port: int
    param_port: int
    params: list            # list of ParamDef
    plots: list             # list of PlotDef (exactly 4 for 2x2 grid)
    include_reset: bool = False
    interval_ms: int = 200
    sidebar_width: str = "280px"
    extra_params: dict = field(default_factory=dict)
    param_builder: object = None  # optional callable(widget_values) -> param_dict


def build_app(config: AppConfig) -> Dash:
    """Generate a complete Dash app from an AppConfig."""

    client = SimulatorClient(
        stream_port=config.stream_port,
        param_port=config.param_port,
    )

    # Connect (non-fatal if simulator isn't running yet)
    try:
        client.connect_stream()
        print(f"Stream connected: {len(client.signal_names)} signals")
    except Exception as e:
        print(f"Stream connection failed (start simulator first): {e}")

    try:
        client.connect_params()
        print(f"Params connected: {client.param_names}")
    except Exception as e:
        print(f"Param connection failed: {e}")

    # Build sidebar
    sidebar_children = [html.H3(config.title, style={"marginTop": "0"})]

    # Group params by group name, preserving order
    groups = OrderedDict()
    for p in config.params:
        groups.setdefault(p.group, []).append(p)

    # Track widget IDs for the callback
    widget_ids = []   # (id_string, kind, param_key)

    for group_name, param_list in groups.items():
        if group_name:
            sidebar_children.append(html.Hr())
            sidebar_children.append(
                html.H4(group_name, style={"marginTop": "8px", "marginBottom": "4px"})
            )
        for p in param_list:
            if p.kind == "dropdown":
                options = p.options or []
                dd_id = f"dd-{p.key}"
                sidebar_children.append(C.make_dropdown(p.key, options, p.default, p.label))
                widget_ids.append((dd_id, "dropdown", p.key))
            else:
                sl_id = f"slider-{p.key}"
                sidebar_children.append(C.make_slider(p.key, p.min, p.max, p.step, p.default, p.label))
                widget_ids.append((sl_id, "slider", p.key))

    # Start/Stop/Reset buttons
    sidebar_children.extend(C.make_start_stop_buttons(include_reset=config.include_reset))

    sidebar = C.make_sidebar(sidebar_children, width=config.sidebar_width)

    # Graph IDs
    graph_ids = [p.graph_id for p in config.plots]

    # Build signal selectors for each plot
    signal_selector_ids = []
    plot_area_children_left = []
    plot_area_children_right = []

    available_signals = list(client.signal_names) if client.signal_names else []

    for i, plot_def in enumerate(config.plots):
        sel_id = f"signal-select-{plot_def.graph_id}"
        signal_selector_ids.append(sel_id)

        default_signals = [t.signal for t in plot_def.traces]

        plot_block = html.Div([
            dcc.Dropdown(
                id=sel_id,
                options=[{"label": s, "value": s} for s in available_signals],
                value=default_signals,
                multi=True,
                searchable=True,
                placeholder="Search and add signals...",
                style={"fontSize": "11px", "marginBottom": "2px",
                       "marginLeft": "4px", "marginRight": "4px"},
            ) if plot_def.user_selectable else html.Div(id=sel_id, style={"display": "none"}),
            dcc.Graph(id=plot_def.graph_id, style={"height": "43vh" if plot_def.user_selectable else "45vh"}),
        ])

        if i < 2:
            plot_area_children_left.append(plot_block)
        else:
            plot_area_children_right.append(plot_block)

    # Build layout manually to include signal selectors
    app = Dash(__name__)
    app.layout = html.Div([
        dcc.Interval(id="interval", interval=config.interval_ms, n_intervals=0),
        html.Div([
            sidebar,
            html.Div([
                html.Div(plot_area_children_left, style={"flex": "1"}),
                html.Div(plot_area_children_right, style={"flex": "1"}),
            ], style={"display": "flex", "flex": "1"}),
        ], style={"display": "flex", "height": "100vh"}),
    ])

    # Register start/stop callbacks
    C.register_start_stop_callbacks(app)

    # Build trace label lookup from config
    trace_label_map = {}
    trace_mode_map = {}
    for plot_def in config.plots:
        for t in plot_def.traces:
            trace_label_map[t.signal] = t.label
            trace_mode_map[t.signal] = t.mode

    # Collect all outputs and inputs for the main callback
    outputs = []
    for plot_def in config.plots:
        outputs.append(Output(plot_def.graph_id, "figure"))
    outputs.append(Output("sim-status", "children"))
    outputs.append(Output("sim-status", "style"))

    inputs = [Input("interval", "n_intervals")]
    # Signal selector inputs
    for sel_id in signal_selector_ids:
        inputs.append(Input(sel_id, "value"))
    if config.include_reset:
        inputs.append(Input("btn-reset", "n_clicks"))

    states = []
    for wid, kind, key in widget_ids:
        states.append(State(wid, "value"))
    states.append(State("store-start-clicks", "data"))
    states.append(State("store-stop-clicks", "data"))

    # Store previous reset clicks for edge detection
    _state = {"prev_reset_clicks": 0}

    @app.callback(outputs, inputs, states)
    def update_graphs(*args):
        idx = 0
        n_intervals = args[idx]; idx += 1

        # Signal selections (one per plot)
        signal_selections = []
        for _ in config.plots:
            signal_selections.append(args[idx]); idx += 1

        reset_clicks = 0
        if config.include_reset:
            reset_clicks = args[idx] or 0; idx += 1

        # Widget values
        widget_values = {}
        for (wid, kind, key) in widget_ids:
            val = args[idx]; idx += 1
            widget_values[key] = float(val) if val is not None else 0.0

        start_clicks = args[idx]; idx += 1
        stop_clicks = args[idx]; idx += 1

        # Build param dict
        if config.param_builder is not None:
            param_dict = config.param_builder(widget_values)
        else:
            param_dict = {key: widget_values.get(key, 0.0) for (_, _, key) in widget_ids}

        # Merge extra params
        param_dict.update(config.extra_params)

        # Start/stop commands
        param_dict["start_cmd"] = float(start_clicks or 0)
        param_dict["stop_cmd"] = float(stop_clicks or 0)

        # Reset edge detection
        if config.include_reset:
            param_dict["reset"] = 1.0 if reset_clicks > _state["prev_reset_clicks"] else 0.0
            _state["prev_reset_clicks"] = reset_clicks

        client.send_params(param_dict)

        # Build figures
        figures = []
        for plot_idx, plot_def in enumerate(config.plots):
            # Use user-selected signals if available, otherwise fall back to config
            selected = signal_selections[plot_idx]
            if selected is None:
                selected = [t.signal for t in plot_def.traces]

            x_data = client.get_history(plot_def.x_signal)

            traces = []
            for sig in selected:
                y_data = client.get_history(sig)
                label = trace_label_map.get(sig, sig)
                mode = trace_mode_map.get(sig, "lines")
                trace = {"x": x_data, "y": y_data, "name": label, "type": "scatter", "mode": mode}
                if mode == "markers":
                    trace["marker"] = {"size": 3, "opacity": 0.6}
                traces.append(trace)

            fig = {
                "data": traces,
                "layout": {
                    "title": plot_def.title,
                    "xaxis": {"title": plot_def.xaxis},
                    "yaxis": {"title": plot_def.yaxis},
                    "margin": {"t": 40},
                },
            }
            figures.append(fig)

        # Status
        default_dur = widget_values.get("duration", 30.0)
        status_text, status_style = C.status_from_stream(client, default_dur)

        return tuple(figures) + (status_text, status_style)

    return app
